28	  /**
29	   * Mode determines what is displayed:
30	   * - "organization": Shows current organization name
31	   * - "account": Shows "My Account" but allows switching to organizations
32	   */
33	  mode?: TeamSwitcherMode;
34	  /** Called when user selects an org — app should handle auth SDK (e.g., clerk.setActive) */
35	  onOrgSelect: (orgId: string, orgSlug: string) => Promise<void>;
36	  /** List of organizations the user belongs to */
37	  organizations: Organization[];
38	}
39	
40	export type { Organization, TeamSwitcherMode, TeamSwitcherProps };
41	
42	export function TeamSwitcher({
43	  organizations,
44	  mode = "organization",
45	  onOrgSelect,
46	  createTeamHref,
