"use client";

import { useTRPC } from "@repo/app-trpc/react";
import { Button } from "@repo/ui/components/ui/button";
import { Icons } from "@repo/ui/components/icons";
import { Check, Circle } from "lucide-react";
import { useRouter } from "next/navigation";
import { useCallback, useEffect, useState } from "react";
import { useOAuthPopup } from "~/hooks/use-oauth-popup";

const ERROR_MESSAGES: Record<string, string> = {
  github_org_bound_to_other:
    "This GitHub organization is already connected to another Lightfast team.",
  org_already_bound:
    "This team is already connected to a different GitHub organization.",
};

interface GitHubBindStepProps {
  orgName: string;
  slug: string;
}

export function GitHubBindStep({ orgName, slug }: GitHubBindStepProps) {
  const router = useRouter();
  const trpc = useTRPC();
  const [error, setError] = useState<string | null>(null);

  // Listen for binding errors from the popup via BroadcastChannel
  useEffect(() => {
    const channel = new BroadcastChannel("oauth-connections");
    channel.onmessage = (event: MessageEvent) => {
      const data = event.data as { type?: string; reason?: string };
