input.new_string:
listUserOrganizations: userScopedProcedure.query(async ({ ctx }) => {
  // userScopedProcedure guarantees clerk-pending or clerk-active
  const userId = ctx.auth.userId;
  const clerk = await clerkClient();

  // Get all organizations the user belongs to from Clerk
  const { data: memberships } =
    await clerk.users.getOrganizationMembershipList({
      userId,
    });

  // Batch-query binding status for all orgs (single indexed SELECT)
  const orgIds = memberships.map((m) => m.organization.id);
  const bindings =
    orgIds.length > 0
      ? await ctx.db
          .select({
            clerkOrgId: githubOrgBindings.clerkOrgId,
            status: githubOrgBindings.status,
          })
          .from(githubOrgBindings)
          .where(inArray(githubOrgBindings.clerkOrgId, orgIds))
      : [];
  const bindingMap = new Map(bindings.map((b) => [b.clerkOrgId, b.status]));

  return memberships.map((membership) => {
    const clerkOrg = membership.organization;

    return {
      id: clerkOrg.id,
      slug: clerkOrg.slug,
      name: clerkOrg.name,
      role: membership.role,
      imageUrl: clerkOrg.imageUrl,
      githubBound: bindingMap.get(clerkOrg.id) === "active",
    };
  });
}),

